#include <stdio.h>
#include <string.h>
#include <stdbool.h>
#define MAX 500000
#define MAX_WORD_LENGTH 16
#define MAX_BOARD_SIZE 16

bool canWin(char board[MAX_BOARD_SIZE][MAX_BOARD_SIZE], int r, int c, char dictionary[MAX][MAX_WORD_LENGTH], int D, bool used[MAX_BOARD_SIZE][MAX_BOARD_SIZE]) {
    for (int i = 0; i < D; i++) {
        bool canFormWord = true;
        for (int j = 0; j < strlen(dictionary[i]); j++) {
            bool found = false;
            for (int x = 0; x < r; x++) {
                for (int y = 0; y < c; y++) {
                    if (!used[x][y] && board[x][y] == dictionary[i][j]) {
                        found = true;
                        used[x][y] = true;
                        break;
                    }
                }
                if (found) break;
            }
            if (!found) {
                canFormWord = false;
                break;
            }
        }
        if (canFormWord) return true;
    }
    return false;
}

int minimax(char board[MAX_BOARD_SIZE][MAX_BOARD_SIZE], int r, int c, char dictionary[MAX][MAX_WORD_LENGTH], int D, bool used[MAX_BOARD_SIZE][MAX_BOARD_SIZE], int depth, bool isMaximizingPlayer) {
    if (canWin(board, r, c, dictionary, D, used)) return 1;
    if (!canWin(board, r, c, dictionary, D, used) && depth == 0) return -1;
    if (isMaximizingPlayer) {
        int bestScore = -1000;
        for (int i = 0; i < r; i++) {
            for (int j = 0; j < c; j++) {
                if (!used[i][j]) {
                    used[i][j] = true;
                    int score = minimax(board, r, c, dictionary, D, used, depth + 1, false);
                    used[i][j] = false;
                    bestScore = (bestScore > score) ? bestScore : score;
                }
            }
        }
        return bestScore;
    } else {
        int bestScore = 1000;
        for (int i = 0; i < r; i++) {
            for (int j = 0; j < c; j++) {
                if (!used[i][j]) {
                    used[i][j] = true;
                    int score = minimax(board, r, c, dictionary, D, used, depth + 1, true);
                    used[i][j] = false;
                    bestScore = (bestScore < score) ? bestScore : score;
                }
            }
        }
        return bestScore;
    }
}

int main() {
    int D;
    scanf("%d", &D);
    char dictionary[MAX][MAX_WORD_LENGTH];
    for (int i = 0; i < D; i++) {
        scanf("%s", dictionary[i]);
    }
    int r, c;
    scanf("%d %d", &r, &c);
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        char board[MAX_BOARD_SIZE][MAX_BOARD_SIZE];
        for (int i = 0; i < r; i++) {
            scanf("%s", board[i]);
        }
        bool used[MAX_BOARD_SIZE][MAX_BOARD_SIZE] = {{false}};
        int score = minimax(board, r, c, dictionary, D, used, 0, true);
        if (score > 0) {
            printf("Alice\n");
        } else {
            printf("Bob\n");
        }
    }
    return 0;
}

